"use client";

import { Children, type ReactNode, useMemo } from "react";
import { useControllableState } from "@/hooks/use-controllable-state";
import { cn } from "@/lib/utils";
import { Chevron } from "../icons/chevron";
import {
  NavigationListGroupContext,
  NavigationListGroupPositionContext,
  useNavigationListGroupContext,
  useNavigationListGroupPositionContext,
} from "./navigation-list-group-context";

export interface NavigationListGroupProps {
  label: string;
  expanded?: boolean;
  defaultExpanded?: boolean;
  onExpandedChange?: (expanded: boolean) => void;
  count?: number;
  variant?: "tree" | "section";
  children: ReactNode;
  className?: string;
}

export function NavigationListGroup({
  label,
  expanded: controlledExpanded,
  defaultExpanded = true,
  onExpandedChange,
  count,
  variant = "section",
  children,
  className,
}: NavigationListGroupProps) {
  const parentGroup = useNavigationListGroupContext();
  const position = useNavigationListGroupPositionContext();

  const [expanded, setExpanded] = useControllableState<boolean>({
    value: controlledExpanded,
    defaultValue: defaultExpanded,
    onChange: onExpandedChange,
  });

  const depth = variant === "tree" ? parentGroup.depth + 1 : 0;

  const linePrefix = useMemo(() => {
    if (variant !== "tree") return "";
    if (depth <= 1) return "";
    const isLast = position?.isLast ?? false;
    return parentGroup.linePrefix + (isLast ? "    " : "│   ");
  }, [variant, depth, position?.isLast, parentGroup.linePrefix]);

  const toggle = () => setExpanded((prev) => !prev);

  const arrayChildren = Children.toArray(children);

  const groupContextValue = useMemo(
    () => ({ variant, depth, linePrefix }),
    [variant, depth, linePrefix],
  );

  const groupLabel =
    variant === "section" && count !== undefined
      ? `${label} (${count})`
      : label;

  const wrappedChildren = (
    <NavigationListGroupContext value={groupContextValue}>
      {arrayChildren.map((child, index) => (
        <NavigationListGroupPositionContext
          key={index}
          value={{ isLast: index === arrayChildren.length - 1 }}
        >
          {child}
        </NavigationListGroupPositionContext>
      ))}
    </NavigationListGroupContext>
  );

  // KEY-024: The toggle is aria-hidden because a <button> inside
  // role="listbox" > role="group" violates aria-required-children.
  // Keyboard collapse requires routing through the listbox navigation
  // system (e.g., a key binding when the group header is highlighted).
  // Until that integration exists, collapse remains pointer-only.
  return (
    <div
      role="group"
      aria-label={groupLabel}
      className={cn(
        variant === "section" && "border-t border-border first:border-t-0",
        className,
      )}
    >
      {variant === "section" ? (
        <div
          aria-hidden="true"
          onClick={toggle}
          className="flex w-full items-center gap-1 px-3 py-2 text-[11px] uppercase tracking-wider text-muted-foreground font-mono cursor-pointer select-none hover:text-foreground/80"
          data-expanded={expanded}
        >
          <span className="text-[10px]">{expanded ? "▼" : "▶"}</span>
          <span>{label}</span>
          {count !== undefined && <span>({count})</span>}
        </div>
      ) : (
        <div
          aria-hidden="true"
          onClick={toggle}
          className="flex w-full items-center py-0.5 text-muted-foreground font-mono text-sm cursor-pointer select-none hover:text-foreground/80"
          data-expanded={expanded}
        >
          {depth > 1 && (
            <span className="text-muted-foreground font-mono">
              {parentGroup.linePrefix}
              {position?.isLast ? "└── " : "├── "}
            </span>
          )}
          <Chevron open={expanded} size="sm" className={depth > 1 ? "mx-1" : "mr-1"} />
          <span>{label}/</span>
        </div>
      )}
      {expanded && wrappedChildren}
    </div>
  );
}

"use client";

import { createContext, useContext } from "react";

export interface NavigationListGroupContextValue {
  variant: "tree" | "section";
  depth: number;
  linePrefix: string;
}

const defaultGroupContext: NavigationListGroupContextValue = {
  variant: "section",
  depth: 0,
  linePrefix: "",
};

export const NavigationListGroupContext = createContext<NavigationListGroupContextValue>(defaultGroupContext);

export function useNavigationListGroupContext() {
  return useContext(NavigationListGroupContext);
}

export interface NavigationListGroupPositionContextValue {
  isLast: boolean;
}

export const NavigationListGroupPositionContext = createContext<NavigationListGroupPositionContextValue | undefined>(undefined);

export function useNavigationListGroupPositionContext() {
  return useContext(NavigationListGroupPositionContext);
}

"use client";

import { cn } from "@/lib/utils";

type ProgressColor = "auto" | "success" | "warning" | "error" | "muted";
type ProgressVariant = "block" | "bar";

export interface NavigationListProgressProps {
  value: number;
  variant?: ProgressVariant;
  width?: number;
  color?: ProgressColor;
  showLabel?: boolean;
  className?: string;
}

const colorClasses: Record<Exclude<ProgressColor, "auto">, string> = {
  success: "text-success",
  warning: "text-warning",
  error: "text-destructive",
  muted: "text-muted-foreground",
};

function resolveColorKey(value: number, color: ProgressColor): Exclude<ProgressColor, "auto"> {
  if (color !== "auto") return color;
  if (value === 0) return "muted";
  if (value >= 80) return "success";
  if (value >= 40) return "warning";
  return "error";
}

function buildBar(variant: ProgressVariant, filled: number, empty: number): string {
  if (variant === "bar") {
    return `[${"=".repeat(filled)}${"-".repeat(empty)}]`;
  }
  return `${"█".repeat(filled)}${"░".repeat(empty)}`;
}

export function NavigationListProgress({
  value: rawValue,
  variant = "block",
  width = 10,
  color = "auto",
  showLabel = true,
  className,
}: NavigationListProgressProps) {
  const value = Math.min(100, Math.max(0, rawValue));
  const filled = Math.round((value / 100) * width);
  const empty = width - filled;
  const bar = buildBar(variant, filled, empty);
  const label = showLabel ? ` ${String(value).padStart(3)}%` : "";
  const colorKey = resolveColorKey(value, color);

  return (
    <span
      role="progressbar"
      aria-valuenow={value}
      aria-valuemin={0}
      aria-valuemax={100}
      aria-label={`${value}% complete`}
      data-color={colorKey}
      className={cn(
        "font-mono text-[10px] whitespace-pre leading-none",
        colorClasses[colorKey],
        "group-data-[active]:text-primary-foreground/70",
        className,
      )}
    >
      {bar}{label}
    </span>
  );
}
